Certainly! Here’s a complete example of a Rust GUI application fulfilling your requirements, using the [`eframe`](https://crates.io/crates/eframe) GUI framework and [`rfd`](https://crates.io/crates/rfd) for cross-platform folder selection dialogs. For file monitoring, we'll use [`notify`](https://crates.io/crates/notify).

---

### `Cargo.toml`

```toml
[package]
name = "folder_monitor_gui"
version = "0.1.0"
edition = "2021"

[dependencies]
eframe = "0.26"
rfd = "0.14"
notify = "6.1"
```

---

### `src/main.rs`

```rust
use std::{
    path::PathBuf,
    sync::mpsc::{self, Sender, Receiver},
    thread,
};

use eframe::{egui, epi};
use notify::{Watcher, RecursiveMode, EventKind};

struct FolderMonitorApp {
    input_path: Option<PathBuf>,
    output_path: Option<PathBuf>,
    done_path: Option<PathBuf>,
    monitoring: bool,
    event_receiver: Option<Receiver<String>>,
    event_log: Vec<String>,
}

impl Default for FolderMonitorApp {
    fn default() -> Self {
        Self {
            input_path: None,
            output_path: None,
            done_path: None,
            monitoring: false,
            event_receiver: None,
            event_log: Vec::new(),
        }
    }
}

impl epi::App for FolderMonitorApp {
    fn name(&self) -> &str {
        "Folder Monitor GUI"
    }

    fn update(&mut self, ctx: &egui::Context, _frame: &epi::Frame) {
        egui::CentralPanel::default().show(ctx, |ui| {
            // Folder selection UI
            ui.horizontal(|ui| {
                if ui.button("Input Folder").clicked() {
                    if let Some(path) = rfd::FileDialog::new().pick_folder() {
                        self.input_path = Some(path);
                    }
                }
                ui.label(
                    self.input_path
                        .as_ref()
                        .map(|p| p.display().to_string())
                        .unwrap_or_else(|| "Not selected".to_string())
                );
            });
            ui.horizontal(|ui| {
                if ui.button("Output Folder").clicked() {
                    if let Some(path) = rfd::FileDialog::new().pick_folder() {
                        self.output_path = Some(path);
                    }
                }
                ui.label(
                    self.output_path
                        .as_ref()
                        .map(|p| p.display().to_string())
                        .unwrap_or_else(|| "Not selected".to_string())
                );
            });
            ui.horizontal(|ui| {
                if ui.button("Done Folder").clicked() {
                    if let Some(path) = rfd::FileDialog::new().pick_folder() {
                        self.done_path = Some(path);
                    }
                }
                ui.label(
                    self.done_path
                        .as_ref()
                        .map(|p| p.display().to_string())
                        .unwrap_or_else(|| "Not selected".to_string())
                );
            });

            ui.add_space(10.0);
            if ui
                .add_enabled(
                    !self.monitoring
                        && self.input_path.is_some()
                        && self.output_path.is_some()
                        && self.done_path.is_some(),
                    egui::Button::new("Start"),
                )
                .clicked()
            {
                self.start_monitoring();
            }

            // Event log display
            ui.separator();
            ui.label("Events:");
            egui::ScrollArea::vertical()
                .max_height(250.0)
                .show(ui, |ui| {
                    for event in &self.event_log {
                        ui.label(event);
                    }
                });

            // Poll the event channel for messages from the watcher thread
            if let Some(event_rx) = &self.event_receiver {
                while let Ok(event_msg) = event_rx.try_recv() {
                    self.event_log.push(event_msg);
                }
            }

            ctx.request_repaint(); // Continuously check the channel
        });
    }
}

impl FolderMonitorApp {
    fn start_monitoring(&mut self) {
        let input_path = self.input_path.as_ref().unwrap().clone();
        let (event_tx, event_rx): (Sender<String>, Receiver<String>) = mpsc::channel();

        // Thread for watcher
        thread::spawn(move || {
            let mut watcher = notify::recommended_watcher(move |res| {
                match res {
                    Ok(event) => {
                        if let Some(path) = event.paths.get(0) {
                            let event_str = match event.kind {
                                EventKind::Create(_) => {
                                    format!("Created: {}", path.display())
                                },
                                EventKind::Modify(_) => {
                                    format!("Modified: {}", path.display())
                                },
                                EventKind::Remove(_) => {
                                    format!("Removed: {}", path.display())
                                },
                                _ => {
                                    format!("Other event: {:?} ({})", event.kind, path.display())
                                }
                            };
                            let _ = event_tx.send(event_str);
                        }
                    },
                    Err(err) => {
                        let _ = event_tx.send(format!("Watch error: {:?}", err));
                    }
                }
            }).expect("Failed to start watcher");

            watcher
                .watch(&input_path, RecursiveMode::NonRecursive)
                .expect("Failed to watch input folder");

            // Keep thread alive
            loop {
                thread::sleep(std::time::Duration::from_secs(1));
                // Optional: check for shutdown signal here
            }
        });

        self.monitoring = true;
        self.event_receiver = Some(event_rx);
        self.event_log.push("Started monitoring input folder...".to_string());
    }
}

fn main() -> eframe::Result<()> {
    let options = eframe::NativeOptions::default();
    eframe::run_native(
        "Folder Monitor GUI",
        options,
        Box::new(|_cc| Box::new(FolderMonitorApp::default())),
    )
}
```

