Below is a **full example** implementing your requirements, modeled after the `CustomerMaintenance` pattern you provided.  
This includes the **Student class**, a static `StudentDB`, a `Validator`, and a simplified `FormStudent` for your Windows Forms application.

---

### 1. Student class

```csharp
namespace StudentMaintenance
{
    public class Student
    {
        public int StudentID { get; set; }
        public string Name { get; set; } = "";
        public decimal GPA { get; set; }

        public override string ToString()
        {
            return $"ID: {StudentID}, Name: {Name}, GPA: {GPA:F2}";
        }
    }
}
```

---

### 2. StudentDB class (Binary I/O)

```csharp
using System;
using System.Collections.Generic;
using System.IO;

namespace StudentMaintenance
{
    public static class StudentDB
    {
        private const string Dir = @"C:\C#\files\";
        private const string Path = Dir + "Students.dat";

        public static void SaveStudents(List<Student> students)
        {
            if (!Directory.Exists(Dir))
                Directory.CreateDirectory(Dir);

            using BinaryWriter binaryOut = new(
                new FileStream(Path, FileMode.Create, FileAccess.Write));

            foreach (Student student in students)
            {
                binaryOut.Write(student.StudentID);
                binaryOut.Write(student.Name);
                binaryOut.Write(student.GPA);
            }
        }

        public static List<Student> GetStudents()
        {
            List<Student> students = new();

            if (!Directory.Exists(Dir))
                Directory.CreateDirectory(Dir);

            using BinaryReader binaryIn = new(
                new FileStream(Path, FileMode.OpenOrCreate, FileAccess.Read));

            while (binaryIn.BaseStream.Position < binaryIn.BaseStream.Length)
            {
                Student student = new()
                {
                    StudentID = binaryIn.ReadInt32(),
                    Name = binaryIn.ReadString(),
                    GPA = binaryIn.ReadDecimal()
                };
                students.Add(student);
            }

            return students;
        }
    }
}
```

---

### 3. Validator class

```csharp
namespace StudentMaintenance
{
    public static class Validator
    {
        public static string LineEnd { get; set; } = "\n";

        public static string IsPresent(string value, string name)
        {
            string msg = "";
            if (string.IsNullOrWhiteSpace(value))
                msg = $"{name} is a required field.{LineEnd}";
            return msg;
        }

        public static string IsDecimal(string value, string name)
        {
            string msg = "";
            if (!decimal.TryParse(value, out _))
                msg = $"{name} must be a valid decimal value.{LineEnd}";
            return msg;
        }

        public static string IsInt32(string value, string name)
        {
            string msg = "";
            if (!int.TryParse(value, out _))
                msg = $"{name} must be a valid integer value.{LineEnd}";
            return msg;
        }

        public static string IsWithinRange(string value, string name, decimal min, decimal max)
        {
            string msg = "";
            if (decimal.TryParse(value, out decimal number))
            {
                if (number < min || number > max)
                    msg = $"{name} must be between {min} and {max}.{LineEnd}";
            }
            return msg;
        }
    }
}
```

---

### 4. The Windows Form (`FormStudent.cs`)

**Place three TextBoxes** (`txtStudentID`, `txtName`, `txtGPA`),  
**two Buttons** (`btnWriteData`, `btnReadData`),  
and a **ListBox** (`lstStudents`).

#### Designer layout suggestion:

- Student ID: `txtStudentID`
- Name: `txtName`
- GPA: `txtGPA`
- [Write Data] button: `btnWriteData`
- [Read Data] button: `btnReadData`
- ListBox: `lstStudents`

#### Code-Behind:

```csharp
using System;
using System.Collections.Generic;
using System.Windows.Forms;

namespace StudentMaintenance
{
    public partial class FormStudent : Form
    {
        private List<Student> students = new();

        public FormStudent()
        {
            InitializeComponent();
        }

        // Write Data to file
        private void btnWriteData_Click(object sender, EventArgs e)
        {
            string msg = "";
            msg += Validator.IsPresent(txtStudentID.Text, "Student ID");
            msg += Validator.IsInt32(txtStudentID.Text, "Student ID");
            msg += Validator.IsPresent(txtName.Text, "Name");
            msg += Validator.IsPresent(txtGPA.Text, "GPA");
            msg += Validator.IsDecimal(txtGPA.Text, "GPA");
            msg += Validator.IsWithinRange(txtGPA.Text, "GPA", 0.0m, 4.0m);

            if (msg != "")
            {
                MessageBox.Show(msg, "Invalid Input");
                return;
            }

            int studentID = int.Parse(txtStudentID.Text);
            string name = txtName.Text.Trim();
            decimal gpa = decimal.Parse(txtGPA.Text);

            Student student = new()
            {
                StudentID = studentID,
                Name = name,
                GPA = gpa
            };

            // Read current students to avoid overwrite
            try
            {
                students = StudentDB.GetStudents();
            }
            catch (Exception ex)
            {
                MessageBox.Show("Error loading student data: " + ex.Message);
                return;
            }
            students.Add(student);

            try
            {
                StudentDB.SaveStudents(students);
                MessageBox.Show("Student data saved.");
            }
            catch (Exception ex)
            {
                MessageBox.Show("Error writing student data: " + ex.Message);
            }
        }

        // Read Data from file
        private void btnReadData_Click(object sender, EventArgs e)
        {
            lstStudents.Items.Clear();

            try
            {
                List<Student> students = StudentDB.GetStudents();
                foreach (var s in students)
                    lstStudents.Items.Add(s.ToString());
            }
            catch (Exception ex)
            {
                MessageBox.Show("Error reading student data: " + ex.Message);
            }
        }
    }
}
```

---

### 5. Form Designer File Changes

- Add controls with the names used above.
- Assign `btnWriteData_Click` to `btnWriteData`'s Click event
- Assign `btnReadData_Click` to `btnReadData`'s Click event

---

### 6. User Experience Points

- The code validates all input prior to writing.
- Binary file is always closed by `using`.
- Exceptions are caught and shown to the user.
- All read students are shown in the ListBox.

---

### 7. Note

- Create the folder `C:\C#\files\` or ensure your app can create it.
- Remember to run Visual Studio as administrator if you have path permission issues, or set your own folder.

