</style>
</head>
<body>
<header>
  <span class="logo">📓 Notepad+</span>
  <button id="themeBtn" title="Switch theme">🌗</button>
</header>
<div class="tabs" id="tabsBar"></div>
<div class="file-actions">
  <button id="newBtn" title="New File (Ctrl+N)">New</button>
  <button id="saveBtn" title="Save File (Ctrl+S)">Save</button>
  <label for="fileInput" style="cursor:pointer;">Open</label>
  <input type="file" id="fileInput" accept=".txt,.js,.html,.css,.json,.md,.py,.java,.xml,*"/>
  <button id="findBtn" title="Find (Ctrl+F)">Find</button>
  <button id="undoBtn" title="Undo (Ctrl+Z)">Undo</button>
  <button id="redoBtn" title="Redo (Ctrl+Y)">Redo</button>
  <button id="readonlyBtn" title="Toggle Readonly (Ctrl+R)">Readonly</button>
</div>
<main>
  <div class="editor-wrap">
    <pre class="linenumbers" id="linenums">1</pre>
    <div id="editor" contenteditable="true" spellcheck="false" autocorrect="off" autocomplete="off"></div>
    <div id="find-box">
      <form id="findForm" onsubmit="return false;">
        <label>Find:</label>
        <input type="text" id="findInput" placeholder="text" />
        <button type="button" id="findNextBtn">Next</button>
        <button type="button" id="findPrevBtn">Prev</button>
        <label><input type="checkbox" id="findCase" />aA</label>
        <label><input type="checkbox" id="findRegex" />Regex</label>
        <button type="button" id="replaceBtn">Replace</button>
        <input type="text" id="replaceInput" placeholder="replace with"/>
        <button type="button" class="close-find" id="findCloseBtn" title="Close">&times;</button>
      </form>
    </div>
  </div>
</main>
<div class="statusbar" id="statusbar">
  <span id="stat-left">Ln 1, Col 1 | Spaces: 4</span>
  <span id="stat-right">UTF-8</span>
</div>
<script>
/**************************
 * Notepad+ - main logic  *
 **************************/

// Supported syntax highlighting modes by file extension
const SYNTAX_MODES = [
  { name:"Plaintext", ext:["txt", "md"], mode:"plain" },
  { name:"JavaScript", ext:["js", "mjs", "json"], mode:"js"},
  { name:"HTML", ext:["html", "htm", "xml"], mode:"html"},
  { name:"CSS", ext:["css", "scss"], mode:"css"},
  { name:"Python", ext:["py"], mode:"py"},
  { name:"Java", ext:["java"], mode:"java"},
  { name:"Markdown", ext:["md"], mode:"md"},
  // Add more by extending here
];

function extOfFilename(name) {
  const m = /\.(\w+)$/.exec(name||"");
  return m&&m[1] ? m[1].toLowerCase() : null;
}
function detectMode(filename) {
  const ext = extOfFilename(filename||"untitled.txt")||"txt";
  for (let mode of SYNTAX_MODES)
    if (mode.ext.includes(ext)) return mode.mode;
  return "plain";
}
// Tab structure: {name, content, mode, history, dirty, readonly }
const TABS = [];

const $ = sel => document.querySelector(sel);
const $$ = sel => document.querySelectorAll(sel);

let currentTab = 0, tabIdCounter = 1;
let updatingEditor = false, updatingTab = false;

function newTab(name, content="", mode, readonly=false) {
  name = name || "untitled-"+tabIdCounter+".txt";
  mode = mode || detectMode(name);
  let tab = {
    name, content, mode,
    history: [], historyIndex: -1,
    dirty: false,
    readonly: readonly,
    id: tabIdCounter++
  };
  TABS.push(tab);
  selectTab(TABS.length-1);
  renderTabs();
}

function selectTab(idx) {
  idx = Math.max(0, Math.min(idx, TABS.length-1));
  currentTab = idx;
  updatingTab = true;
  const tab = TABS[idx];
  let cont = tab.content;
  setEditorContent(cont||"");
  setSyntaxMode(tab.mode);
  setReadonly(tab.readonly);
  updateLineNumbers();
  renderTabs();
  updatingTab = false;
}

function closeTab(idx) {
  if (TABS.length === 1) {
    TABS[0].content = "";
    TABS[0].name = "untitled-"+tabIdCounter+".txt";
    TABS[0].mode = "plain";
    TABS[0].dirty = false;
    TABS[0].history = [];
    renderTabs();
    setEditorContent("");
    setSyntaxMode("plain");
    updateLineNumbers();
    return;
  }
  TABS.splice(idx,1);
  currentTab = Math.max(0, currentTab-1);
  selectTab(currentTab);
  renderTabs();
}

function renderTabs() {
  const tabsBar = $("#tabsBar");
  tabsBar.innerHTML = "";
  TABS.forEach((tab,i)=>{
    const el=document.createElement("button");
    el.className = "tab"+(i===currentTab?" active":"");
    let d = tab.dirty ? "*" : "";
    el.innerHTML = `<span>${tab.name.replace(/</g,"&lt;")}${d}</span>
      <button class="close" tabindex="-1" title="Close">&times;</button>`;
    el.onclick = e => {
      if (e.target.classList.contains("close")) closeTab(i);
      else selectTab(i);
    };
    tabsBar.appendChild(el);
  });
}
function getCurrentTab() {return TABS[currentTab]}
function updateCurrentTabContent(value) {
  let tab = getCurrentTab();
  if (!tab.readonly) {
    tab.content = value;
    tab.dirty = true;
  }
}

function setSyntaxMode(mode) {
  $("#editor").setAttribute("data-mode", mode);
}
function setReadonly(readonly) {
  $("#editor").setAttribute("contenteditable", String(!readonly));
  $("#readonlyBtn").innerText = readonly ? "Edit" : "Readonly";
}
function getCaretPos() {
  let sel = window.getSelection();
  if (!sel || sel.rangeCount==0) return 0;
  let range = sel.getRangeAt(0);
  return range.startOffset;
}

function setEditorContent(val) {
  updatingEditor = true;
  $("#editor").innerText = val;
  highlightEditor();
  updateLineNumbers();
  updatingEditor = false;
}
function getEditorContent() { return $("#editor").innerText; }
function insertTextAtCursor(text) {
  let sel = window.getSelection();
  if (!sel.rangeCount) return;
  let range = sel.getRangeAt(0);
  range.deleteContents();
  range.insertNode(document.createTextNode(text));
  // Move caret to after inserted text
  range.setStartAfter(range.endContainer);
  range.collapse(true);
  sel.removeAllRanges();
  sel.addRange(range);
}
// --------------- Syntax highlighting logic -------------------
function escape(str) {
  return str.replace(/&/g,"&amp;")
    .replace(/</g,"&lt;")
    .replace(/>/g,"&gt;");
}
function highlightLine(text, mode) {
  if (mode=="js" || mode=="json") return highlightJS(text);
  if (mode=="html" || mode=="xml") return highlightHTML(text);
  if (mode=="css") return highlightCSS(text);
  if (mode=="py") return highlightPy(text);
  if (mode=="java") return highlightJava(text);
  if (mode=="md") return highlightMD(text);
  return escape(text);
}

function highlightEditor() {
  let tab = getCurrentTab();
  let lines = getEditorContent().split("\n");
  let mode = tab.mode;
  let l = lines.map(ln=>highlightLine(ln, mode)).join("\n");
  // For selection: Save caret/cursor
  let editor = $("#editor");
  let scrollT = editor.scrollTop, scrollL = editor.scrollLeft;
  let sel = window.getSelection(), pos, anchorNode;
  if (sel.rangeCount > 0) {
    let range = sel.getRangeAt(0);
    pos = range.startOffset;
    anchorNode = range.startContainer;
  }
  editor.innerHTML = l;
  // Restore caret position (approximate)
  if (pos !== undefined && anchorNode) {
    try {
      let node = editor.childNodes[sel.anchorOffset] || editor.lastChild;
      if (node) {
        let r = document.createRange();
        r.setStart(node, Math.min(pos, node.textContent.length));
        r.collapse(true);
        sel.removeAllRanges();
        sel.addRange(r);
      }
    } catch(e){}
  }
  editor.scrollTop = scrollT;
  editor.scrollLeft = scrollL;
  updateLineNumbers();
}
function updateLineNumbers() {
  let lines = getEditorContent().split('\n').length;
  $("#linenums").innerHTML = Array.from({length:lines},(_,i)=>i+1).join('\n') || '1';
}
// -------------- Styles for popular languages --------------
// JS
function highlightJS(line) {
  // Comments
  line = line.replace(/(\/\/.*)/g,'<span class="syntax-comment">$1</span>');
  // Regex literal
  line = line.replace(/([^\\])((\/(\\\/|[^\/\n])+\/[gimsuy]{0,5}))/g,
    '$1<span class="syntax-regex">$2</span>');
  // Strings
  line = line.replace(/(['"`])(?:(?=(\\?))\2.)*?\1/g,
    s=>`<span class="syntax-string">${escape(s)}</span>`);
  // Numbers
  line = line.replace(/\b\d+(\.\d+)?\b/g, '<span class="syntax-number">$&</span>');
  // Keywords
  line = line.replace(
    /\b(var|let|const|function|class|if|else|return|while|for|in|of|break|continue|try|catch|finally|throw|new|this|super|extends|typeof|void|case|switch|delete|await|async|null|undefined|true|false)\b/g,
    '<span class="syntax-keyword">$1</span>');
  // Built-ins
  line = line.replace(/\b(Array|String|Object|Number|Boolean|JSON|Math|Date|RegExp|Error|parseInt|parseFloat|encodeURI|decodeURI|console|window|document|setTimeout|setInterval|require|import|export|Promise|Map|Set|WeakMap|WeakSet|Symbol)\b/g,
    '<span class="syntax-builtin">$1</span>');
  // Functions
  line = line.replace(/\b([a-z_]\w*)\s*(?=\()/gi, '<span class="syntax-function">$1</span>');
  // Operators
  line = line.replace(/([=+\-*\/%<>!|&]+)/g, '<span class="syntax-operator">$1</span>');
  return line;
}
// HTML
function highlightHTML(line) {
  // Comments
  line = line.replace(/(&lt;!--[\s\S]*?--&gt;)/g,
    '<span class="syntax-comment">$1</span>');
  // Tags/elements
  line = line.replace(/(&lt;\/?)([a-z0-9-]+)(.*?)(\/?&gt;)/gi,
    function(_,a,tag,attrs,e){
      let r = `${a}<span class="syntax-tag">${tag}</span>`;
      if(attrs){
        r+=attrs.replace(/\s+([\w-:]+)(=("[^"]*"|'[^']*'))?/g,
          (__,attr,val,quote)=>` <span class="syntax-attr">${attr}</span>${val||""}`
        );
      }
      return r+e;
    });
  // Entities
  line = line.replace(/&amp;[a-z0-9#]+;/gi,
    '<span class="syntax-number">$&</span>');
  return escape(line).replace(/&lt;(!--[\s\S]*?--)&gt;/g,
    '<span class="syntax-comment">&lt;$1&gt;</span>');
}
// CSS
function highlightCSS(line) {
  line = escape(line);
  // Comments
  line = line.replace(/(\/\*.*\*\/)/g,
    '<span class="syntax-comment">$1</span>');
  // Selectors
  line = line.replace(/^([^\{\}]+)\{/,
    '<span class="syntax-selector">$1</span>{');
  // Properties
  line = line.replace(/([a-z-]+)\s*:/gi,
    '<span class="syntax-property">$1</span>:');
  // Numbers/units
  line = line.replace(/(\b\d+(\.\d+)?)(px|rem|em|%|deg|vh|vw)?/gi,
    '<span class="syntax-number">$1</span>$3');
  // Strings
  line = line.replace(/("[^"]*"|'[^']*')/g,
    '<span class="syntax-string">$1</span>');
  // Classes/ids
  line = line.replace(/([.#][a-zA-Z0-9_-]+)/g,
    '<span class="syntax-class">$1</span>');
  return line;
}
// Python
function highlightPy(line) {
  // Comments
  line = line.replace(/(#.*)/g,
    '<span class="syntax-comment">$1</span>');
  // Strings
  line = line.replace(/(['"]{3}[\s\S]*?['"]{3}|(['"])(?:(?=(\\?))\3.)*?\2)/g,
    '<span class="syntax-string">$1</span>');
  // Keywords
  line = line.replace(
    /\b(def|class|if|else|elif|return|for|in|while|break|continue|try|except|finally|raise|from|import|as|pass|with|lambda|yield|True|False|None|and|or|not|is|global|nonlocal|assert)\b/g,
    '<span class="syntax-keyword">$1</span>');
  // Built-ins
  line = line.replace(/\b(print|len|dict|list|set|int|str|float|open|range|input|enumerate|zip|map|filter|sum|isinstance|type|object|super)\b/g,
    '<span class="syntax-builtin">$1</span>');
  // Functions
  line = line.replace(/\b([a-z_][a-z0-9_]*)\s*(?=\()/gi,
    '<span class="syntax-function">$1</span>');
  // Operators
  line = line.replace(/([\+\-*\/%=&|><!]+)/g,'<span class="syntax-operator">$1</span>');
  // Numbers
  line = line.replace(/\b\d+(\.\d+)?\b/g,'<span class="syntax-number">$&</span>');
  return line;
}
// Java
function highlightJava(line) {
  // Comments
  line = line.replace(/(\/\/.*)/g,
    '<span class="syntax-comment">$1</span>');
  // Strings
  line = line.replace(/("[^"]*")/g,'<span class="syntax-string">$1</span>');
  // Keywords
  line = line.replace(
    /\b(package|import|public|private|protected|static|class|interface|extends|implements|void|int|float|boolean|double|char|new|return|if|else|switch|case|break|continue|for|while|do|try|catch|finally|throw|throws|this|super|instanceof|enum|const|goto|null|true|false)\b/g,
    '<span class="syntax-keyword">$1</span>');
  // Builtins
  line = line.replace(/\b(System|Math|String|Integer|Object|Exception|Thread|ArrayList|println)\b/g,
    '<span class="syntax-builtin">$1</span>');
  // Numbers
  line = line.replace(/\b\d+(\.\d+)?\b/g,'<span class="syntax-number">$&</span>');
  // Operators
  line = line.replace(/([\+\-*\/%=&|><!]+)/g,'<span class="syntax-operator">$1</span>');
  // Functions
  line = line.replace(/\b([a-z_][a-z0-9_]*)\s*(?=\()/gi,
    '<span class="syntax-function">$1</span>');
  return line;
}
// Markdown
function highlightMD(line) {
  // Headers
  line = line.replace(/^(#+)(.*)/,`<span class="syntax-keyword">$1</span><b>$2</b>`);
  // Bold
  line = line.replace(/\*\*(.*?)\*\*/g, `<b>$1</b>`);
  // Italic
  line = line.replace(/_(.*?)_/g, `<i>$1</i>`);
  // Links
  line = line.replace(/\[([^\]]+)\]\(([^)]+)\)/g,
    `<span class="syntax-builtin">[$1]($2)</span>`);
  // Inline code
  line = line.replace(/`([^`]+)`/g,`<span class="syntax-string">\`$1\`</span>`);
  // Lists
  line = line.replace(/^(\s*[-*+] )/g,
    `<span class="syntax-class">$1</span>`);
  return line;
}

// -------------- File Operations -------------- //
$("#saveBtn").onclick = function() {
  let tab = getCurrentTab();
  let blob = new Blob([tab.content], {type:"text/plain"});
  let a = document.createElement("a");
  a.download = tab.name;
  a.href = URL.createObjectURL(blob);
  a.click();
  tab.dirty = false;
  renderTabs();
};

$("#newBtn").onclick = function() {
  newTab();
}

$("#fileInput").onchange = function(e) {
  let file = e.target.files[0];
  if (!file) return;
  let reader = new FileReader();
  reader.onload = function(evt) {
    newTab(file.name, evt.target.result, detectMode(file.name));
  };
  reader.readAsText(file);
  this.value = "";
};

// ------------- Undo / Redo ------------- //
$("#undoBtn").onclick = function() {editorUndo();};
$("#redoBtn").onclick = function() {editorRedo();};
function editorUndo() {
  let tab = getCurrentTab();
  if (tab.historyIndex <= 0) return;
  tab.historyIndex--;
  setEditorContent(tab.history[tab.historyIndex]);
  updateCurrentTabContent(tab.history[tab.historyIndex]);
}
function editorRedo() {
  let tab = getCurrentTab();
  if(tab.historyIndex >= tab.history.length-1) return;
  tab.historyIndex++;
  setEditorContent(tab.history[tab.historyIndex]);
  updateCurrentTabContent(tab.history[tab.historyIndex]);
}
function saveHistory() {
  let tab = getCurrentTab();
  let cont = getEditorContent();
  if (tab.history[tab.historyIndex] === cont) return;
  tab.history = tab.history.slice(0, tab.historyIndex+1);
  tab.history.push(cont);
  tab.historyIndex = tab.history.length-1;
  if (tab.history.length > 50) {
    tab.history.shift();
    tab.historyIndex--;
  }
}
$("#readonlyBtn").onclick = function() {
  let tab = getCurrentTab();
  tab.readonly = !tab.readonly;
  setReadonly(tab.readonly);
};

// ----------- Editor events ----------- //
$("#editor").addEventListener("input", function(e){
  if (updatingEditor||updatingTab) return;
  let val = getEditorContent();
  updateCurrentTabContent(val);
  saveHistory();
  highlightEditor();
  updateSecondary();
});
$("#editor").addEventListener("keydown", function(e){
  // Tab indent
  if (e.key=="Tab") {
    e.preventDefault();
    document.execCommand('insertText', false, "    ");
  } else if (e.key=="Enter") {
    // Auto-indent
    let sel = window.getSelection();
    let textUptoCaret = getEditorContent().slice(0, getCaretAbsolutePosition());
    let lines = textUptoCaret.split('\n');
    let prevLine = lines[lines.length-1]||"";
    let indent = (/^\s*/.exec(prevLine)||[""])[0];
    setTimeout(()=>document.execCommand('insertText', false, indent),0);
  }
  // Shortcuts
  if (e.ctrlKey) {
    if (e.key.toLowerCase() === "s") {
      e.preventDefault(); $("#saveBtn").click();
    } else if (e.key.toLowerCase() === "f") {
      e.preventDefault(); showFindBox();
    } else if (e.key.toLowerCase() === "n") {
      e.preventDefault(); newTab();
    } else if (e.key.toLowerCase() === "r") {
      e.preventDefault(); $("#readonlyBtn").click();
    } else if (e.key.toLowerCase() === "z") {
      e.preventDefault(); editorUndo();
    } else if (e.key.toLowerCase() === "y") {
      e.preventDefault(); editorRedo();
    }
  }
  // Highlight on the fly
  setTimeout(() => highlightEditor(), 0);
});
$("#editor").addEventListener('scroll', function(e) {
  $("#linenums").scrollTop = this.scrollTop;
});

$("#tabsBar").onwheel = function(ev) {
  this.scrollLeft += ev.deltaY*0.53;
};

function getCaretAbsolutePosition() {
  let sel = window.getSelection();
  if (!sel.rangeCount) return 0;
  let range = sel.getRangeAt(0);
  let preSelRange = range.cloneRange();
  preSelRange.selectNodeContents($("#editor"));
  preSelRange.setEnd(range.endContainer, range.endOffset);
  return preSelRange.toString().length;
}

// ---------- Status Bar + Utils ---------- //
function updateSecondary() {
  // Line/col
  let caret = getCaretAbsolutePosition();
  let text = getEditorContent().substr(0, caret);
  let lines = text.split('\n');
  let ln = lines.length, col = lines[ln-1].length+1;
  $("#stat-left").innerText = `Ln ${ln}, Col ${col} | Spaces: 4`;
}
$("#editor").addEventListener("click", updateSecondary);
$("#editor").addEventListener("keyup", updateSecondary);

// ---------- THEME -------- //
let theme = localStorage.getItem("theme") || "dark";
function setThemeMode(dark) {
  theme = dark?"dark":"light";
  document.body.className = dark?"":"light";
  $("#themeBtn").innerText = dark ? "🌗" : "🌞";
  localStorage.setItem('theme', theme);
}
$("#themeBtn").onclick = function(){
  setThemeMode(theme=="light");
};
setThemeMode(theme=="light" ? false : true);

// ------------- FIND/REPLACE ----------- //
let findMatches = [], findIndex = -1;

$("#findBtn").onclick = showFindBox;
$("#findCloseBtn").onclick = hideFindBox;

function hideFindBox() {
  $("#find-box").style.display = "none";
  $("#editor").focus();
}

function showFindBox() {
  $("#find-box").style.display = "block";
  $("#findInput").focus();
  findUpdate();
}

// Find logic
function findUpdate() {
  let str = $("#findInput").value;
  if (!str) {clearHighlights(); findMatches=[]; return;}
  let content = getEditorContent();
  let mode =  $("#findRegex").checked ? "regex" : "plain";
