```hcl
variable "cluster_name" {
  description = "ECS Cluster name. If empty, will create a new one."
  type        = string
  default     = ""
}

variable "desired_count" {
  type        = number
  default     = 1
}

variable "image_url" {
  description = "ECR Image URL to deploy"
  type        = string
}

variable "warp_token_ssm_param" {
  description = "SSM parameter name for Cloudflare WARP token"
  type        = string
}

variable "service_name" {
  type        = string
  default     = "cloudflare-warp"
}

data "aws_region" "current" {}

resource "aws_ecs_cluster" "this" {
  count = var.cluster_name == "" ? 1 : 0

  name = var.service_name
}

locals {
  cluster_id = var.cluster_name != "" ? var.cluster_name : aws_ecs_cluster.this[0].name
}

resource "aws_ecs_task_definition" "this" {
  family                   = "${var.service_name}-task"
  network_mode             = "awsvpc"
  requires_compatibilities = ["FARGATE"]
  cpu                      = "256"
  memory                   = "512"
  execution_role_arn       = aws_iam_role.ecs_task_execution_role.arn
  task_role_arn            = aws_iam_role.ecs_task_execution_role.arn

  container_definitions = jsonencode([
    {
      name      = "warp"
      image     = var.image_url
      essential = true
      environment = [
        {
          name = "WARP_TOKEN"
          valueFrom = var.warp_token_ssm_param
        }
      ]
      logConfiguration = {
        logDriver = "awslogs"
        options = {
          awslogs-group         = "/ecs/${var.service_name}"
          awslogs-region        = data.aws_region.current.name
          awslogs-stream-prefix = "ecs"
        }
      }
    }
  ])
}

resource "aws_ecs_service" "this" {
  name            = var.service_name
  cluster         = local.cluster_id
  task_definition = aws_ecs_task_definition.this.arn
  desired_count   = var.desired_count
  launch_type     = "FARGATE"

  network_configuration {
    subnets         = var.subnet_ids
    assign_public_ip = true
    security_groups = var.security_group_ids
  }

  depends_on = [
    aws_ecs_task_definition.this
  ]
}

# --- Required IAM roles for task execution ---
resource "aws_iam_role" "ecs_task_execution_role" {
  name = "${var.service_name}-ecs-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Effect = "Allow"
      Principal = {
        Service = "ecs-tasks.amazonaws.com"
      }
      Action = "sts:AssumeRole"
    }]
  })
}

resource "aws_iam_role_policy_attachment" "ecs_task_execution_policy" {
  role       = aws_iam_role.ecs_task_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonECSTaskExecutionRolePolicy"
}

resource "aws_iam_role_policy_attachment" "ssm_policy" {
  role       = aws_iam_role.ecs_task_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSSMReadOnlyAccess"
}


# --- CODEPIPELINE skeleton ---
resource "aws_codepipeline" "this" {
  name     = "${var.service_name}-pipeline"
  role_arn = aws_iam_role.pipeline_role.arn

  artifact_store {
    location = var.s3_bucket
    type     = "S3"
  }

