Absolutely! Here’s a clean and scalable approach for a SwiftUI voice recorder with a dynamic equalizer animation, structured for best practices:

### Features:

- **MVVM Architecture** for separation of concerns.
- Uses **AVAudioRecorder** for audio recording.
- **Combine** publishers for live audio level updates.
- **Reusable EqualizerView** animates based on mic input.
- **Permission handling**.
- **Recorded file saved to Documents directory**.

---

### 1. VoiceRecorderViewModel.swift

```swift
import Foundation
import AVFoundation
import Combine

class VoiceRecorderViewModel: NSObject, ObservableObject {
    @Published var isRecording = false
    @Published var currentLevel: Float = 0.0  // Ranges from 0 (silence) to 1 (max)
    @Published var recordingURL: URL?
    @Published var recordingError: String?

    private var audioRecorder: AVAudioRecorder?
    private var timer: Timer?

    override init() {
        super.init()
    }

    func requestPermission() {
        AVAudioSession.sharedInstance().requestRecordPermission { _ in }
    }

    func startRecording() {
        let session = AVAudioSession.sharedInstance()
        do {
            try session.setCategory(.playAndRecord, mode: .default)
            try session.setActive(true)

            let settings: [String: Any] = [
                AVFormatIDKey: Int(kAudioFormatMPEG4AAC),
                AVSampleRateKey: 12000,
                AVNumberOfChannelsKey: 1,
                AVEncoderAudioQualityKey: AVAudioQuality.high.rawValue
            ]

            let url = Self.getNewRecordingURL()
            audioRecorder = try AVAudioRecorder(url: url, settings: settings)
            audioRecorder?.isMeteringEnabled = true
            audioRecorder?.delegate = self
            audioRecorder?.record()
            isRecording = true
            recordingURL = nil
            recordingError = nil

            startLevelMonitoring()
        } catch {
            recordingError = "Failed to start recording: \(error.localizedDescription)"
        }
    }

    func stopRecording() {
        audioRecorder?.stop()
        stopLevelMonitoring()
        isRecording = false
    }

    private func startLevelMonitoring() {
        timer = Timer.scheduledTimer(withTimeInterval: 0.05, repeats: true) { [weak self] _ in
            guard let self = self, let recorder = self.audioRecorder else { return }
            recorder.updateMeters()
            let normalized = max(0, min(1, (recorder.averagePower(forChannel: 0) + 60) / 60))
            self.currentLevel = normalized
        }
    }
    private func stopLevelMonitoring() {
        timer?.invalidate()
        timer = nil
        currentLevel = 0
    }

    static func getNewRecordingURL() -> URL {
        let formatter = DateFormatter()
        formatter.dateFormat = "yyyyMMdd_HHmmss"
        let fileName = "Recording_\(formatter.string(from: Date())).m4a"
        let url = FileManager.default.urls(for: .documentDirectory, in: .userDomainMask).first!
        return url.appendingPathComponent(fileName)
    }
}

extension VoiceRecorderViewModel: AVAudioRecorderDelegate {
    func audioRecorderDidFinishRecording(_ recorder: AVAudioRecorder, successfully flag: Bool) {
        if flag {
            recordingURL = recorder.url
        } else {
            recordingError = "Recording failed."
        }
    }
}
```

---

### 2. EqualizerView.swift

```swift
import SwiftUI

struct EqualizerView: View {
    let level: Float       // 0.0 ... 1.0
    let barCount: Int = 10
    let minBarHeight: CGFloat = 10
    let maxBarHeight: CGFloat = 40
    let spacing: CGFloat = 4

    var body: some View {
        HStack(alignment: .center, spacing: spacing) {
            ForEach(0..<barCount, id: \.self) { i in
                Capsule()
                    .fill(Color.accentColor)
                    .frame(
                        width: 4,
                        height: barHeight(for: i)
                    )
                    .animation(.linear(duration: 0.07), value: level)
            }
        }
        .frame(height: maxBarHeight)
    }

    // Creates a wave-like effect across bars
    private func barHeight(for index: Int) -> CGFloat {
        let normalized = Double(level)
        let phase = Double(index) / Double(barCount - 1) * Double.pi
        let wave = sin(normalized * Double.pi + phase)
        let rawHeight = minBarHeight + CGFloat(abs(wave)) * (maxBarHeight - minBarHeight)
        return rawHeight
    }
}
```

---

### 3. VoiceRecorderView.swift

```swift
import SwiftUI

struct VoiceRecorderView: View {
    @StateObject private var viewModel = VoiceRecorderViewModel()

    var body: some View {
        VStack(spacing: 32) {
            Spacer()

            if viewModel.isRecording {
                Text("Recording…").font(.headline)
                    .foregroundStyle(.secondary)
            } else {
                Text("Ready to record").font(.headline)
            }

            EqualizerView(level: viewModel.currentLevel)
                .padding()
                .frame(width: 80, height: 60)

            Spacer()

            HStack(spacing: 40) {
                Button(action: { viewModel.startRecording() }) {
                    Label("Record", systemImage: "circle.fill")
                        .labelStyle(.iconOnly)
                        .font(.system(size: 48))
                        .foregroundStyle(viewModel.isRecording ? .secondary : .red)
                        .opacity(viewModel.isRecording ? 0.5 : 1.0)
                }
                .disabled(viewModel.isRecording)

                Button(action: { viewModel.stopRecording() }) {
                    Label("Stop", systemImage: "stop.fill")
                        .labelStyle(.iconOnly)
                        .font(.system(size: 48))
                        .foregroundStyle(viewModel.isRecording ? .red : .secondary)
                        .opacity(!viewModel.isRecording ? 0.5 : 1.0)
                }
                .disabled(!viewModel.isRecording)
            }

            if let url = viewModel.recordingURL, !viewModel.isRecording {
                Text("Saved at \(url.lastPathComponent)")
                    .font(.footnote)
                    .foregroundStyle(.green)
            }
            if let error = viewModel.recordingError {
                Text("Error: \(error)").foregroundStyle(.red).font(.footnote)
            }

            Spacer()
        }
        .padding()
        .onAppear {
            viewModel.requestPermission()
        }
    }
}
```

