```javascript
// Simple file system using a JS object
const fileSystem = {
  '/': {
    type: 'folder',
    children: {
      'Documents': {type: 'folder', children: {}},
      'New File.txt': {type: 'file', content: "Type your notes here!\n"}
    }
  }
};

let windowsZ = 2, windowIdx = 0;

// Utility functions
function pathJoin(...parts) {
  return parts.join('/').replace(/\/+/g, '/').replace(/\/$/, '') || '/';
}
function getNode(path) {
  const parts = path === '/' ? [] : path.replace(/^\//, '').split('/');
  let node = fileSystem['/'];
  for (let p of parts) {
    if (!node.children[p]) return null;
    node = node.children[p];
  }
  return node;
}
function basename(path) {
  return path === '/' ? '/' : path.split('/').pop();
}
function dirname(path) {
  if (path === '/' || !path.includes('/')) return '/';
  return path.replace(/\/+$/, '').replace(/\/[^/]+$/,'') || '/';
}

// Window Manager
function createWindow({title, contentFn, width=440, height=310, appId, options={}}) {
  const win = document.createElement('div');
  win.className = "window";
  win.style.width = width+"px";
  win.style.height = height+"px";
  win.style.left = (60+Math.random()*120)+'px';
  win.style.top = (60+Math.random()*60)+'px';
  win.style.zIndex = windowsZ++;

  win.setAttribute('data-window-id', 'w'+(++windowIdx));
  if (appId) win.setAttribute('data-app', appId);

  // Titlebar
  win.innerHTML = `
    <div class="titlebar">
      <span class="title">${title}</span>
      <span class="window-btns">
        <button class="window-btn close">&times;</button>
      </span>
    </div>
    <div class="window-content"></div>
  `;
  const contentDiv = win.querySelector('.window-content');
  contentFn(contentDiv, win);

  // Drag & Focus
  let dragOffX = 0, dragOffY = 0, dragging = false;
  const tb = win.querySelector('.titlebar');
  tb.onmousedown = function(e){
    dragging = true;
    dragOffX = e.clientX - win.offsetLeft;
    dragOffY = e.clientY - win.offsetTop;
    win.style.zIndex = windowsZ++;
    document.body.style.userSelect = 'none';
  };
  window.onmousemove = function(e){
    if (dragging) {
      win.style.left = Math.max(0, e.clientX - dragOffX) + 'px';
      win.style.top = Math.max(0, e.clientY - dragOffY) + 'px';
    }
  };
  window.onmouseup = function(e){
    dragging = false;
    document.body.style.userSelect = '';
  };

  win.onmousedown = ()=> { win.style.zIndex = windowsZ++; }

  // Close button
  win.querySelector('.window-btn.close').onclick = function(){
    win.remove();
  };

  document.getElementById('windows').appendChild(win);
  return win;
}

// File Explorer app
function launchFileExplorer(path='/') {
  createWindow({
    title: "File Explorer",
    appId: "fileexplorer",
    width: 450,
    height: 330,
    contentFn: function(cdiv, win){
      let curPath = path;

      function refresh() {
        cdiv.innerHTML = "";

        // Toolbar
        const toolbar = document.createElement('div');
        toolbar.className = "file-explorer-toolbar";
        toolbar.innerHTML = `
          <button id="fe-new-folder">New Folder</button>
          <button id="fe-new-file">New File</button>
          <button id="fe-up">Up</button>
          <input type="text" value="${curPath}" size="10" id="fe-path">
        `;
        cdiv.appendChild(toolbar);

        // List files
        const node = getNode(curPath);
        const ul = document.createElement('ul');
        ul.className = "file-list";

        let parent = dirname(curPath);
        if (curPath !== '/') {
            const li = document.createElement('li');
            li.innerHTML = '<img src="https://img.icons8.com/fluency/24/up--v1.png"/>.. (parent)';
            li.onclick = () => { curPath = parent; refresh();};
            ul.appendChild(li);
        }

        for (let [name, file] of Object.entries(node.children)) {
          const li = document.createElement('li');
          if (file.type === 'folder') {
            li.innerHTML = `<img src="https://img.icons8.com/fluency/24/folder-invoices.png"/>${name}`;
            li.onclick = () => { curPath = pathJoin(curPath, name); refresh(); };
          } else {
            li.innerHTML = `<img src="https://img.icons8.com/fluency/24/note.png"/>${name}`;
            li.onclick = () => { launchNotepad(curPath+'/'+name);}
          }

          // Right-click for delete/rename
          li.oncontextmenu = function(e){
            e.preventDefault();
            let menu = document.createElement('div');
            menu.style.position = 'fixed';
            menu.style.left = e.clientX+'px';
            menu.style.top = e.clientY+'px';
            menu.style.background = '#fff';
            menu.style.border = '1px solid #b0b0c8';
            menu.style.borderRadius = '4px';
            menu.style.padding = '0';
            menu.style.zIndex = 9999;
            menu.innerHTML = `<div style="padding:7px;cursor:pointer;" id="fe-delete">Delete</div>
              <div style="padding:7px;cursor:pointer;" id="fe-rename">Rename</div>`;
            document.body.appendChild(menu);

            menu.onclick = function(e2) {
              if (e2.target.id === 'fe-delete') {
                if (confirm('Delete "'+name+'"?')) {
                  delete node.children[name];
                  menu.remove();
                  refresh();
                }
              } else if (e2.target.id === 'fe-rename') {
                let newname = prompt('Enter new name:', name);
                if (newname && newname !== name) {
                  node.children[newname] = file;
                  delete node.children[name];
                  menu.remove();
                  refresh();
                }
              }
            };
            document.body.onclick = ()=>menu.remove();
          };

          ul.appendChild(li);
        }
        cdiv.appendChild(ul);

        // Handlers - New Folder/File
        toolbar.querySelector('#fe-new-folder').onclick = function(){
          let fname = prompt('Folder name:');
          if (fname && !node.children[fname]) {
            node.children[fname] = {type:'folder', children: {}};
            refresh();
          }
        };
        toolbar.querySelector('#fe-new-file').onclick = function(){
          let fname = prompt('File name:');
          if (fname && !node.children[fname]) {
            node.children[fname] = {type:'file', content:""};
            refresh();
          }
        };
        toolbar.querySelector('#fe-up').onclick = function(){
          if (curPath !== '/') { curPath = dirname(curPath); refresh(); }
        };
        toolbar.querySelector('#fe-path').onkeydown = function(e){
          if (e.key === 'Enter') {
            let p = toolbar.querySelector('#fe-path').value;
            if (getNode(p)) { curPath = p; refresh(); }
            else alert('Path not found.');
          }
        };
      }
      refresh();
    }
  });
}

// Notepad app; path optional
function launchNotepad(path=null) {
  let origValue = '';
  createWindow({
    title: "Notepad" + (path ? " - " + basename(path) : ""),
    appId: "notepad",
    width: 430,
    height: 320,
    contentFn: (cdiv, win)=>{
      let value = "";
      if (path) {
        let node = getNode(path);
        value = node && node.type === 'file' ? node.content : "";
        origValue = value;
      }
      cdiv.innerHTML = `
        <textarea id="notepad-textarea">${value}</textarea><br>
        <button id="notepad-save">Save</button>
        <span id="save-status" style="margin-left:6px;color:#434cac;"></span>
      `;
      cdiv.querySelector('#notepad-save').onclick = function(){
        if (path) {
          let node = getNode(path);
          if (node) {
            node.content = cdiv.querySelector('#notepad-textarea').value;
            cdiv.querySelector('#save-status').innerText = "Saved!";
            setTimeout(()=>cdiv.querySelector('#save-status').innerText='',700);
            origValue = node.content;
          }
        } else {
          alert('Notepad is not linked to a file. Use File Explorer to edit file.');
        }
      };
    }
  });
}

// Desktop icon events
document.querySelectorAll('.desktop-icon').forEach(icon=>{
  icon.ondblclick = function(){
    let app = icon.dataset.app;
    if (app === 'fileexplorer') launchFileExplorer('/');
    else if (app === 'notepad') launchNotepad();
  };
  // Single click: select effect
  icon.onclick = function(){
    document.querySelectorAll('.desktop-icon').forEach(i=>i.style.background='');
    icon.style.background='#1330ab33';
  };
});

// Optional: Deselect icons when clicking desktop
document.getElementById('desktop').onclick = function(e){
  if (e.target === this) document.querySelectorAll('.desktop-icon').forEach(i=>i.style.background='');
};

// Boot: display windows container
document.getElementById('windows').style.display = 'block';
```

