Certainly! Let's create a minimal Unity **geometry shader** that:

- Takes a source texture (with alpha/transparent pixels)
- For each *non-transparent* pixel, generates a quad in 3D space
- Each quad is **extruded** along its normal by a user-defined factor

Below is a .shader file which contains a vertex, geometry, and fragment shader in Unity's syntax, along with notes.

---

### 1. Shader Code

```shader
Shader "Custom/ExtrudedTextureQuads"
{
    Properties
    {
        _MainTex("Main Texture", 2D) = "white" {}
        _AlphaCutoff("Alpha Cutoff", Range(0,1)) = 0.1
        _Extrude("Extrude Distance", Float) = 0.2
    }
    SubShader
    {
        Tags { "RenderType"="Opaque" }
        Pass
        {
            Cull Off // So both sides of quads are visible if needed

            CGPROGRAM
            #pragma vertex vert
            #pragma geometry geom
            #pragma fragment frag
            #pragma target 4.0

            #include "UnityCG.cginc"

            sampler2D _MainTex;
            float4 _MainTex_TexelSize;
            float _AlphaCutoff;
            float _Extrude;

            struct appdata
            {
                float4 vertex : POSITION;
                float2 uv : TEXCOORD0;
            };

            struct v2g
            {
                float4 vertex : POSITION; // In object space
                float2 uv : TEXCOORD0;
            };

            struct g2f
            {
                float4 vertex : SV_POSITION;
                float2 uv : TEXCOORD0;
            };

            v2g vert(appdata v)
            {
                v2g o;
                o.vertex = v.vertex;
                o.uv = v.uv;
                return o;
            }

            [maxvertexcount(4)]
            void geom(point v2g IN[1], inout TriangleStream<g2f> triStream)
            {
                // Determine texel size (pixel size in UV coordinates)
                float2 texel = float2(_MainTex_TexelSize.x, _MainTex_TexelSize.y);

                // Sample the pixel's alpha
                float alpha = tex2D(_MainTex, IN[0].uv).a;
                if (alpha < _AlphaCutoff)
                    return; // Don't emit a quad for transparent pixel

                // Define quad in object space using texel size
                float3 center = IN[0].vertex.xyz;
                float2 uvCenter = IN[0].uv;

                float3 quadVerts[4];
                float2 quadUVs[4];

                quadVerts[0] = center + float3(-texel.x*0.5, -texel.y*0.5, 0);
                quadVerts[1] = center + float3(-texel.x*0.5,  texel.y*0.5, 0);
                quadVerts[2] = center + float3( texel.x*0.5,  texel.y*0.5, 0);
                quadVerts[3] = center + float3( texel.x*0.5, -texel.y*0.5, 0);

                quadUVs[0] = uvCenter + float2(-texel.x*0.5, -texel.y*0.5);
                quadUVs[1] = uvCenter + float2(-texel.x*0.5,  texel.y*0.5);
                quadUVs[2] = uvCenter + float2( texel.x*0.5,  texel.y*0.5);
                quadUVs[3] = uvCenter + float2( texel.x*0.5, -texel.y*0.5);

                // Calculate normal (assuming flat XY plane)
                float3 normal = float3(0, 0, 1);

                // Extrude along normal
                for (int i = 0; i < 4; i++)
                {
                    quadVerts[i] += normal * _Extrude;
                }

                // Output as a triangle strip (quad)
                g2f o;
                [unroll]
                for (int i = 0; i < 4; i++)
                {
                    o.vertex = UnityObjectToClipPos(float4(quadVerts[i],1));
                    o.uv = quadUVs[i];
                    triStream.Append(o);
                }
            }

            fixed4 frag(g2f i) : SV_Target
            {
                return tex2D(_MainTex, i.uv);
            }
            ENDCG
        }
    }
    FallBack "Diffuse"
}
```

---

### 2. Usage instructions

- **Assign this shader to a material.**
- Use a plane or quad mesh with sufficient subdivisions (e.g. a grid with as many vertices as the texture's _pixels_) so each pixel gets a vertex. A single quad with only 4 vertices will NOT work.
- Set the texture in `_MainTex`.
- Adjust `_AlphaCutoff` to the threshold for transparency.
- Set extrusion with `_Extrude`.

#### For testing:
- Use a plane with a mesh of (texture width)x(texture height) subdivisions (import a grid mesh if needed), so each vertex is at a UV corresponding to one texture pixel.

---

### 3. Explanation

- **Vertex shader**: Passes vertex position and UV.
- **Geometry shader**: For each input point, checks the corresponding texture alpha. If it's opaque, emits a quad (as a triangle strip) in local space, extruded along normal.
- **Fragment shader**: Just samples and outputs the texture color.

---

### 4. Notes

- This code expects to receive **one point per pixel**; it does **NOT** work if you just use a single quad (with 4 vertices).
- For a standard Unity Quad or Plane, you'll need to generate a grid mesh whose vertices are mapped 1:1 to the desired pixels of your texture or write a script to supply "per-pixel" points.
- The geometry shader receives one point per input vertex.

---

**If you want a setup that works with a generic quad mesh, you must instead "iterate" in the geometry shader over texel coordinates, which can be more complex and less efficient. Usually, it's best to generate point geometry in advance, or procedurally using a compute shader or custom mesh.**

