### Code: `todo.py`

```python
import sys

def is_prime(n):
    if n < 2:
        return False
    if n == 2:
        return True
    if n % 2 == 0:
        return False
    for i in range(3, int(n**0.5) + 1, 2):
        if n % i == 0:
            return False
    return True

def next_prime(primes):
    n = primes[-1] + 1 if primes else 2
    while True:
        if is_prime(n):
            primes.append(n)
            return n
        n += 1

def load_todos():
    try:
        with open("todos.txt", "r") as f:
            lines = f.readlines()
            todos = [line.strip().split('\t', 1) for line in lines]
            return [(text, status == "1") for text, status in todos]
    except FileNotFoundError:
        return []

def save_todos(todos):
    with open("todos.txt", "w") as f:
        for text, done in todos:
            f.write(f"{text}\t{int(done)}\n")

def add_todo(todo, todos):
    todos.append((todo, False))
    save_todos(todos)
    print("Todo added.")

def complete_todo(number, todos):
    incompleted_todos = [i for i, (text, done) in enumerate(todos) if not done]
    if not (1 <= number <= len(incompleted_todos)):
        print("Invalid todo number.")
        return
    idx = incompleted_todos[number-1]
    todos[idx] = (todos[idx][0], True)
    save_todos(todos)
    print("Todo marked as completed.")

def list_todos(todos):
    incompleted = [(i+1, text) for i, (text, done) in enumerate(todos) if not done]
    completed = []
    primes = []
    for text, done in todos:
        if done:
            completed.append((next_prime(primes), text))
    if incompleted:
        print("Incomplete Todos:")
        for num, text in incompleted:
            print(f"  {num}. {text}")
    else:
        print("No incomplete todos!")
    if completed:
        print("\nCompleted Todos:")
        for num, text in completed:
            print(f"  {num}. {text}")

def usage():
    print("Usage:")
    print("  python todo.py add <todo>")
    print("  python todo.py list")
    print("  python todo.py complete <number>")

def main():
    todos = load_todos()
    if len(sys.argv) < 2:
        usage()
        return

    command = sys.argv[1]
    if command == "add":
        if len(sys.argv) < 3:
            print("No todo provided.")
            return
        todo = ' '.join(sys.argv[2:])
        add_todo(todo, todos)
    elif command == "list":
        list_todos(todos)
    elif command == "complete":
        if len(sys.argv) != 3 or not sys.argv[2].isdigit():
            print("Please provide the number of the todo to complete.")
            return
        complete_todo(int(sys.argv[2]), todos)
    else:
        usage()

if __name__ == "__main__":
    main()
```

