}

//--- NGINX DEPLOYMENT ---

nginxDeployment: Deployment & {
    metadata: {
        name:   appLabels.nginx.name
        labels: appLabels.nginx
        namespace: clusterName
    }
    spec: {
        replicas: 1
        selector: matchLabels: appLabels.nginx
        template: {
            metadata: labels: appLabels.nginx
            spec: {
                containers: [{
                    name:  appLabels.nginx.name
                    image: "nginx:alpine"
                    ports: [{ containerPort: 80 }]
                    volumeMounts: [{
                        name:      "nginx-conf"
                        mountPath: "/etc/nginx/conf.d"
                    }]
                }]
                volumes: [{
                    name: "nginx-conf"
                    configMap: name: "nginx-config"
                }]
            }
        }
    }
}

//--- NGINX SERVICE ---

nginxService: Service & {
    metadata: {
        name:   appLabels.nginx.name
        labels: appLabels.nginx
        namespace: clusterName
    }
    spec: {
        selector: appLabels.nginx
        ports: [{
            port:       80
            targetPort: 80
        }]
        type: "LoadBalancer" // or "NodePort" if preferred
    }
}

//--- NGINX CONFIGMAP ---

nginxConfigMap: {
    apiVersion: "v1"
    kind:       "ConfigMap"
    metadata: {
        name: "nginx-config"
        namespace: clusterName
    }
    data: {
        "homeassistant.conf": '''
        server {
            listen 80;
            location / {
                proxy_pass         http://home-assistant:8123;
                proxy_set_header   Host $host;
                proxy_set_header   X-Real-IP $remote_addr;
                proxy_set_header   X-Forwarded-For $proxy_add_x_forwarded_for;
                proxy_set_header   X-Forwarded-Proto $scheme;
            }
        }
        '''
    }
}
```

**How this works:**

- `namespace` sets up a dedicated namespace.
- `haDeployment` and `nginxDeployment` define one pod each (you can scale by changing `replicas`).
- `haService` exposes Home Assistant (not publicly).
- `nginxDeployment` includes a volume mount for its config, coming from `nginxConfigMap`.
- `nginxService` exposes nginx for external access; change `type` as needed.
- `nginxConfigMap` holds the nginx reverse-proxy configuration.

