#ifndef CHART2D_FLTK_H
#define CHART2D_FLTK_H

#include <FL/Fl_Widget.H>
#include <string>
#include <vector>
#include <memory>

// Simple 2D point struct
struct Point {
    float x;
    float y;
    Point(float _x = 0, float _y = 0) : x(_x), y(_y) {}
};

// Each graph (data set) on the chart
struct ChartGraph {
    std::string name;
    Fl_Color color;
    std::vector<Point> points;
    ChartGraph(const std::string& n = "", Fl_Color c = FL_BLACK)
        : name(n), color(c) {}
};

class Chart2D : public Fl_Widget {
public:
    // Grid and axis display settings
    struct GridSettings {
        bool show_grid = true;
        int x_grid_count = 5;
        int y_grid_count = 5;
        Fl_Color grid_color = FL_LIGHT2;
        int grid_line_style = FL_DASH;
    };

private:
    // Core data
    std::vector<std::unique_ptr<ChartGraph>> graphs_;
    std::string x_axis_name_;
    std::string y_axis_name_;

    float x_min_, x_max_, y_min_, y_max_; // Viewport bounds

    GridSettings grid_;

    // Internal helper
    void draw_axes();
    void draw_grid();
    void draw_graphs();

    // Utility to map data coords to screen coords
    int map_x(float x) const;
    int map_y(float y) const;

public:
    // Constructor
    Chart2D(int X, int Y, int W, int H,
            const char* l=0);

    // Redraw/resize handling
    void resize(int X, int Y, int W, int H) override;
    void draw() override;

    // ==== Chart/Axis settings ====
    void set_axis_names(const std::string& x_name, const std::string& y_name);
    void set_axis_bounds(float x_min, float x_max, float y_min, float y_max);
    void set_grid_settings(const GridSettings& grid);

    // ==== Graph/curve management ====
    // Adds a new graph, returns its index
    int add_graph(const std::string& name, Fl_Color color = FL_BLACK);

    // Remove graph by index, returns true if found
    bool remove_graph(int graph_index);

    // Add/Remove point to specific graph
    bool add_point(int graph_index, float x, float y);
    bool remove_point(int graph_index, size_t point_index);

    // Rename graph
    bool rename_graph(int graph_index, const std::string& new_name);

    // ==== Info methods ====
    int graph_count() const;
    std::string graph_name(int graph_index) const;
    int point_count(int graph_index) const;
    std::string x_axis_name() const { return x_axis_name_; }
    std::string y_axis_name() const { return y_axis_name_; }
    float x_min() const { return x_min_; }
    float x_max() const { return x_max_; }
    float y_min() const { return y_min_; }
    float y_max() const { return y_max_; }
    const GridSettings& grid_settings() const { return grid_; }
};

#endif // CHART2D_FLTK_H
```

---

**Explanation:**

- Each "chart" or "curve" is a `ChartGraph` (struct), containing a name, color, and a vector of points.
- You can add/remove graphs, and add/remove points from any graph.
- Axis names and bounds are settable.
- Grid can be customized via `GridSettings`.
- Public info/query methods let you extract details about the chart.
