Certainly! Here’s a **step-by-step example** for creating an infinite scrolling table in Vue 3 **(with Pinia, JavaScript, and a REST API)**, ensuring:

- **Infinite scroll**: Fetches new rows as you near the list's end.
- **Fixed header**: Header stays visible.
- **Dynamic space filling**: Table fills the available vertical space.
- **Pinia store**: Handles fetching rows using `start` and `count` parameters.

---

### 1. Pinia Store (`stores/tableData.js`)

```js
import { defineStore } from 'pinia'
import axios from 'axios'

export const useTableDataStore = defineStore('tableData', {
  state: () => ({
    rows: [],
    loading: false,
    hasMore: true,
    totalCount: 0,
    start: 0,
    count: 30,
  }),
  actions: {
    async loadMoreRows() {
      if (this.loading || !this.hasMore) return
      this.loading = true

      // Use your API endpoint and params here. For demo, using placeholder
      try {
        const response = await axios.get('/api/rows', {
          params: {
            start: this.start,
            count: this.count,
          },
        })
        // Example: { data: {rows: [...], total: 120} }
        const data = response.data

        this.rows.push(...data.rows)
        this.totalCount = data.total
        this.start += data.rows.length
        if (this.rows.length >= data.total || data.rows.length === 0) {
          this.hasMore = false
        }
      } catch (e) {
        // Handle error (e.g., set hasMore false if you want to avoid retry loop)
        console.error(e)
      }
      this.loading = false
    },

    // Reset (for reload, etc)
    async resetAndReload() {
      this.rows = []
      this.hasMore = true
      this.start = 0
      await this.loadMoreRows()
    }
  }
})
```

---

### 2. Table Component (`components/InfiniteTable.vue`)

```vue
<template>
  <div class="infinite-table-container" ref="container" @scroll="onScroll">
    <table class="full-width-table">
      <thead>
        <tr>
          <th>ID</th>
          <th>Name</th>
          <th>Other Field</th>
        </tr>
      </thead>
      <tbody>
        <tr v-for="row in rows" :key="row.id">
          <td>{{ row.id }}</td>
          <td>{{ row.name }}</td>
          <td>{{ row.other }}</td>
        </tr>
        <tr v-if="loading">
          <td colspan="3" class="loading-row">Loading…</td>
        </tr>
      </tbody>
    </table>
    <div v-if="!hasMore && rows.length" class="end-marker">No more data</div>
  </div>
</template>

<script setup>
import { ref, onMounted, nextTick, watch } from 'vue'
import { useTableDataStore } from '@/stores/tableData'

const store = useTableDataStore()
const container = ref(null)
// Destructure for easy access
const { rows, loading, hasMore } = store

// Try to fill the initial space with enough rows
async function tryToFillViewport() {
  await nextTick()
  const el = container.value
  if (!el) return
  const needsFilling = el.scrollHeight <= el.clientHeight && hasMore.value
  if (needsFilling) {
    await store.loadMoreRows()
    // Check again (recursive if needed)
    if (el.scrollHeight <= el.clientHeight && hasMore.value) {
      await tryToFillViewport()
    }
  }
}

async function onScroll() {
  const el = container.value
  if (!el || loading.value || !hasMore.value) return

  // If near the bottom, load more
  const threshold = 150
  if (el.scrollTop + el.clientHeight >= el.scrollHeight - threshold) {
    await store.loadMoreRows()
  }
}

onMounted(async () => {
  if (!rows.length) {
    await store.loadMoreRows()
    await tryToFillViewport()
  }
})

// Optionally, watch for table/container resizing (optional advanced)
</script>

