To compute the \( n \)-th Fibonacci number efficiently for **very large values of \( n \)**, the standard recursive or iterative methods are far too slow. The **fastest (deterministic) method** is via **matrix exponentiation** (also known as the "fast doubling" or "exponentiation by squaring" approach), which computes \( F(n) \) in \( O(\log n) \) time.

Here is an extremely efficient implementation using the **fast doubling algorithm** in pure Python. It works with arbitrarily large integers (Python's `int`):

```python
def fib(n):
    def fib_pair(n):
        if n == 0:
            return (0, 1)
        else:
            a, b = fib_pair(n // 2)
            c = a * (2 * b - a)
            d = a * a + b * b
            if n % 2 == 0:
                return (c, d)
            else:
                return (d, c + d)
    return fib_pair(n)[0]
```

### How it works

- The helper `fib_pair(n)` returns the tuple **(F(n), F(n+1))**.
- The algorithm is based on the doubling identities:
    - \( F(2k) = F(k)[2F(k+1) - F(k)] \)
    - \( F(2k+1) = F(k+1)^2 + F(k)^2 \)
- Time complexity: **O(log n)**

### Example Usage

```python
print(fib(100))     # 354224848179261915075
print(fib(1000000)) # handles very large values!
```

This implementation is **extremely fast** and works efficiently for huge \( n \) (e.g., n > 1,000,000). No external libraries required, just pure arithmetic!

这是一个经典的**矩形面积并**问题，通常用**扫描线+线段树**来处理。由于数据 n <= 50，实际上更暴力的方法也能通过，但出题人要求“章节: 线段树”，因此我们采用正宗的扫描线+离散化+线段树做法。

下面呈上完整的C++代码，并附详细注释：

```cpp
#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;
typedef long long ll;
const int MOD = 1e9+7;

// 线段树模板，维护每个区间的覆盖长度
struct SegmentTree {
    vector<int> cnt; // 覆盖次数
    vector<ll> len;  // 覆盖区间长度
    int n;
    vector<ll> y; // 离散化y坐标，y[i]表示第i个区间的下端点

    SegmentTree(vector<ll>& y_): y(y_) {
        n=y.size()-1; // y坐标n+1段
        cnt.resize(n*4);
        len.resize(n*4);
    }

    void update(int l, int r, int val, int id=1, int L=0, int R=-1) {
        if(R==-1) R = n-1;
        if(r<L||l>R) return;
        if(l<=L && R<=r) {
            cnt[id] += val;
            pushup(id, L, R);
            return;
        }
        int M = (L+R)/2;
        update(l, r, val, id*2, L, M);
        update(l, r, val, id*2+1, M+1, R);
        pushup(id, L, R);
    }
    void pushup(int id, int L, int R) {
        if(cnt[id]>0)
            len[id] = y[R+1] - y[L];
        else if(L<R)
            len[id] = len[id*2] + len[id*2+1];
        else
            len[id] = 0;
    }
    ll query() { return len[1]; }
};

// 事件
struct Event {
    ll x;
    int y1, y2;
    int type; // 1: 入, -1: 出
    Event(ll x, int y1, int y2, int type): x(x), y1(y1), y2(y2), type(type) {}
    bool operator <(const Event& o) const {
        return x < o.x;
    }
};

int main() {
    int n;
    cin>>n;
    vector<vector<ll>> rects(n,vector<ll>(4));
    vector<ll> yy;
    for(int i=0;i<n;i++) {
        ll x1,y1,x2,y2;
        cin>>x1>>y1>>x2>>y2;
        rects[i][0]=x1, rects[i][1]=y1, rects[i][2]=x2, rects[i][3]=y2;
        // 为离散化y收集值
        yy.push_back(y1);
        yy.push_back(y2);
    }
    // 离散化y坐标
    sort(yy.begin(),yy.end());
    yy.erase(unique(yy.begin(),yy.end()),yy.end());
    int m=yy.size();
    // 准备事件
    vector<Event> events;
    for(int i=0;i<n;i++) {
        ll x1=rects[i][0], y1=rects[i][1], x2=rects[i][2], y2=rects[i][3];
        int l = lower_bound(yy.begin(), yy.end(), y1)-yy.begin();
        int r = lower_bound(yy.begin(), yy.end(), y2)-yy.begin();
        events.emplace_back(x1, l, r-1, 1);
        events.emplace_back(x2, l, r-1, -1);
    }
    sort(events.begin(),events.end());
    // 扫描
    SegmentTree seg(yy);
    ll ans=0;
    for(int i=0;i<events.size();i++) {
        if(i > 0) {
            ll dx = events[i].x - events[i-1].x;
            ll covered = seg.query();
            ans = (ans + dx%MOD * covered%MOD)%MOD;
        }
        seg.update(events[i].y1, events[i].y2, events[i].type);
    }
    cout<<ans<<endl;
    return 0;
}
```

### 代码说明
- 首先将所有**纵坐标离散化**（yy），并为线段树做准备。
- 构造事件列表：每个矩形产生两个事件，分别对应其左边（入）和右边（出）。每个事件记录x，以及其在离散y坐标的区间。
- 事件按x排序，从左到右依次处理。每步用线段树维护**当前被任意矩形覆盖的y轴总长度**。
- 累加面积时，当前长度 × 横向移动距离。
- 注意每一步要取模。

### 注意点
- 由于x、y最大可以到 \(10^9\)，最终答案超过64位，要用`long long`且及时取模！
- 线段树维护的是**区间长度和**，不是计数。
- 离散化是避免线段树过大/超限的关键。

