#include <algorithm>
#include <set>
#include <cmath>
using namespace std;
typedef long long ll;

ll gcd(ll a,ll b) { return b?gcd(b,a%b):a; }

vector<int> getDigits(ll x) {
    vector<int> res;
    while(x) {
        res.push_back(x%1'000'000'000'LL);
        x /= 1'000'000'000'LL;
    }
    return res;
}

// 将 x 拆成 k进制下各位（低到高）
vector<int> toBase(ll x, int base) {
    vector<int> res;
    while(x) {
        res.push_back(x%base);
        x/=base;
    }
    return res;
}

// 获取所有大于等于lower的g约数
vector<ll> getDivs(ll g, ll lower) {
    vector<ll> res;
    for(ll i=1;i*i<=g;i++) {
        if(g%i==0) {
            if(i>=lower) res.push_back(i);
            if(i!=g/i && g/i>=lower) res.push_back(g/i);
        }
    }
    return res;
}

// 单组处理
void solve(ll a, ll b, ll c) {
    // 长度只需要到最大那个的长度
    vector<ll> A, B, C;
    ll ta=a, tb=b, tc=c;
    while(ta > 0 || tb > 0 || tc > 0) {
        A.push_back(ta%10);
        B.push_back(tb%10);
        C.push_back(tc%10);
        ta/=10; tb/=10; tc/=10;
    }
    // 但真正分位需要到哪？下标最大只有log_k(max(a,b,c))+1
    vector<ll> S;
    ll x=a, y=b, z=c;
    while(x > 0 || y > 0 || z > 0) {
        S.push_back((x%10)+(y%10)-(z%10));
        x/=10; y/=10; z/=10;
    }
    // 更正规地，应直接按数位提取
    vector<int> va, vb, vc;
    ll aa=a, bb=b, cc=c;
    while(aa || bb || cc) {
        va.push_back(aa%10); aa/=10;
        vb.push_back(bb%10); bb/=10;
        vc.push_back(cc%10); cc/=10;
    }
    ll N=max({a,b,c});

    // 下面才是真正的实现
    vector<ll> sa, sb, sc;
    ll ta1=a, tb1=b, tc1=c;
    while(ta1||tb1||tc1) {
        sa.push_back(ta1%10); ta1/=10;
        sb.push_back(tb1%10); tb1/=10;
        sc.push_back(tc1%10); tc1/=10;
    }
    // 用同一长度
    int len=max({sa.size(), sb.size(), sc.size()});
    sa.resize(len,0);
    sb.resize(len,0);
    sc.resize(len,0);
    vector<ll> diff;
    for(int i=0;i<len;++i) diff.push_back(sa[i]+sb[i]-sc[i]);
    int allzero=1;
    for(auto d:diff) if(d!=0) allzero=0;
    if(allzero) {
        // 无穷多
        cout<<"-1\n";
        return;
    }
    ll g=0;
    for(auto d:diff) if(d!=0) g = gcd(g,abs(d));
    // k in [2,+inf), 且k|g
    set<ll> ks;
    for(ll i=1;i*i<=g;i++) {
        if(g%i==0) {
            if(i>=2) ks.insert(i);
            if(g/i>=2) ks.insert(g/i);
        }
    }
    // k also must > {current maxbase of inputs}
    // 实际上进制的合法最小值: max位数上最大+1
    ll min_k=0;
    ll ta2=a, tb2=b, tc2=c;
    while(ta2 || tb2 || tc2) {
        min_k = max({min_k, ta2%10, tb2%10, tc2%10});
        ta2/=10; tb2/=10; tc2/=10;
    }
    min_k+=1;
    vector<ll> res;
    for(auto k:ks) {
        if(k>=min_k) res.push_back(k);
    }
    cout<<res.size()<<"\n";
}

