        // k|g 且k>=maxdigit+1 且k>=2
        set<ll> res;
        for(ll i=1;i*i<=g;++i) {
            if(g%i==0) {
                if(i>=max(2LL,maxdigit+1)) res.insert(i);
                if(g/i>=max(2LL,maxdigit+1)) res.insert(g/i);
            }
        }
        cout<<res.size()<<"\n";
    }
    return 0;
}
